import React, { createContext, useState, useContext, useEffect } from 'react';

const DataContext = createContext(null);

export const DataProvider = ({ children }) => {
  // --- MOCK DATA ---
  const [staffList, setStaffList] = useState([
    { id: '1', name: 'Nguyễn Văn A', username: 'admin', password: '123', role: 'chief', status: 'active' },
    { id: '2', name: 'Trần Thị B', username: 'staff1', password: '123', role: 'staff', ubi1Base: 5000000, ubi1Percent: 100, status: 'active' },
    { id: '3', name: 'Lê Văn C', username: 'scheduler', password: '123', role: 'scheduler', status: 'active' }, // Tài khoản mẫu Scheduler
  ]);

  const [tasks, setTasks] = useState([]);
  const [disciplineTypes] = useState([
    { id: 'd1', name: 'Trừ 10% KPI', status: 'Active' },
    { id: 'd2', name: 'Cảnh cáo', status: 'Active' }
  ]);

  // STATE MỚI: Lịch công tác (Scheduler)
  const [schedules, setSchedules] = useState([]);

  // STATE MỚI: Dữ liệu chấm công giả lập cho Báo cáo Staff
  const [attendanceLogs, setAttendanceLogs] = useState([
    { id: 1, userId: '2', date: '2023-10-25', checkIn: '07:55', checkOut: '17:00', status: 'Đúng giờ' },
    { id: 2, userId: '2', date: '2023-10-26', checkIn: '08:15', checkOut: '17:30', status: 'Trễ' },
    { id: 3, userId: '2', date: '2023-10-27', checkIn: '07:50', checkOut: '17:05', status: 'Đúng giờ' },
    // Thêm dữ liệu mẫu...
  ]);

  // --- ACTIONS ---
  const addStaff = (newStaff) => {
    const id = Date.now().toString();
    setStaffList([...staffList, { ...newStaff, id }]);
  };

  const updateStaffInfo = (id, updates) => {
    setStaffList(staffList.map(s => s.id === id ? { ...s, ...updates } : s));
  };

  const deleteStaff = (id) => {
    setStaffList(staffList.filter(s => s.id !== id));
  };

  const addTask = (newTask) => {
    const id = Date.now().toString();
    setTasks([...tasks, { ...newTask, id, progress: 0, status: 'pending' }]);
  };

  const deleteTask = (id) => {
    setTasks(tasks.filter(t => t.id !== id));
  };

  // --- SCHEDULER ACTIONS ---
  const addSchedule = (schedule) => {
    const id = Date.now().toString();
    setSchedules([...schedules, { ...schedule, id }]);
  };

  const updateSchedule = (id, updatedSchedule) => {
    setSchedules(schedules.map(s => s.id === id ? { ...s, ...updatedSchedule } : s));
  };

  const deleteSchedule = (id) => {
    setSchedules(schedules.filter(s => s.id !== id));
  };

  return (
    <DataContext.Provider value={{ 
      staffList, addStaff, updateStaffInfo, deleteStaff,
      tasks, addTask, deleteTask,
      disciplineTypes,
      schedules, addSchedule, updateSchedule, deleteSchedule, // Export Scheduler func
      attendanceLogs // Export Attendance logs
    }}>
      {children}
    </DataContext.Provider>
  );
};

export const useData = () => useContext(DataContext);
